#include<bits/stdc++.h>
using namespace std;
long long mod;
struct segment_tree
{
    struct node
    {
        long long l,r,sum;
        long long lson,rson;
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=a[a[x].lson].sum*a[a[x].rson].sum%mod;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=1;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long z)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].sum=z;
            return;
        }
        update(a[x].lson,p,z);
        update(a[x].rson,p,z);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        return getsum(a[x].lson,l,r)*getsum(a[x].rson,l,r)%mod;
    }
}t;
int main()
{
    long long T;
    scanf("%lld",&T);
    while(T--)
    {
        long long q;
        scanf("%lld%lld",&q,&mod);
        t.cnt=0;
        t.init(1,q);
        for(long long i=1;i<=q;i++)
        {
            long long op,x;
            scanf("%lld%lld",&op,&x);
            if(op==1)
            {
                t.update(1,i,x);
            }
            else
            {
                t.update(1,x,1);
            }
            printf("%lld\n",t.getsum(1,1,i));
        }
    }
    return 0;
}
